import{_ as t,c as o,a1 as a,o as h}from"./chunks/framework.BDxlaA_J.js";const d=JSON.parse('{"title":"Công cụ Quét Windows","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/2-scanning-networks/6-WindowsTools.md","filePath":"vi/categories/ethical-hacking-labs/2-scanning-networks/6-WindowsTools.md"}'),r={name:"vi/categories/ethical-hacking-labs/2-scanning-networks/6-WindowsTools.md"};function e(c,n,i,g,s,l){return h(),o("div",null,n[0]||(n[0]=[a('<h1 id="cong-cu-quet-windows" tabindex="-1">Công cụ Quét Windows <a class="header-anchor" href="#cong-cu-quet-windows" aria-label="Permalink to &quot;Công cụ Quét Windows&quot;">​</a></h1><h2 id="colasoft-packet-builder" tabindex="-1">Colasoft Packet Builder <a class="header-anchor" href="#colasoft-packet-builder" aria-label="Permalink to &quot;Colasoft Packet Builder&quot;">​</a></h2><p>Colasoft Packet Builder cho phép tạo các gói tin mạng tùy chỉnh; người dùng có thể sử dụng công cụ này để kiểm tra khả năng bảo vệ mạng trước các cuộc tấn công và kẻ xâm nhập. Colasoft Packet Builder bao gồm một tính năng chỉnh sửa rất mạnh mẽ. Ngoài việc chỉnh sửa dữ liệu thô HEX thông thường, nó có tính năng Decode Editor cho phép người dùng chỉnh sửa giá trị trường giao thức cụ thể dễ dàng hơn nhiều.</p><p>Người dùng cũng có thể chỉnh sửa thông tin giải mã trong hai trình chỉnh sửa - Decode Editor và Hex Editor. Người dùng có thể chọn một trong các mẫu được cung cấp: Ethernet Packet, ARP Packet, IP Packet, TCP Packet và UDP Packet, và thay đổi các tham số trong trình chỉnh sửa giải mã, trình chỉnh sửa thập lục phân hoặc trình chỉnh sửa ASCII để tạo gói tin. Bất kỳ thay đổi nào sẽ được hiển thị ngay lập tức trong hai cửa sổ khác. Ngoài việc xây dựng gói tin, Colasoft Packet Builder cũng hỗ trợ lưu gói tin vào file gói tin và gửi gói tin qua mạng. [Free/Paid] <a href="https://www.colasoft.com/packet_builder/" target="_blank" rel="noreferrer">https://www.colasoft.com/packet_builder/</a></p><h2 id="netscantools-pro" tabindex="-1">NetScanTools Pro <a class="header-anchor" href="#netscantools-pro" aria-label="Permalink to &quot;NetScanTools Pro&quot;">​</a></h2><p>NetScanTools Pro là bộ sưu tập tích hợp các tiện ích thu thập thông tin internet và khắc phục sự cố mạng dành cho Chuyên gia Mạng. Nghiên cứu địa chỉ IPv4, địa chỉ IPv6, tên máy chủ, tên miền, địa chỉ email và URL tự động** hoặc với các công cụ thủ công. Nó được thiết kế cho hệ điều hành Windows. [Trial/Paid] <a href="https://www.netscantools.com/" target="_blank" rel="noreferrer">https://www.netscantools.com/</a></p><h2 id="ip-tools" tabindex="-1">IP-Tools <a class="header-anchor" href="#ip-tools" aria-label="Permalink to &quot;IP-Tools&quot;">​</a></h2><p>IP-Tools bao gồm nhiều công cụ riêng lẻ, từ giám sát băng thông cơ bản đến giả mạo và giải mã. Bạn có thể quét các máy chủ đang hoạt động, quét ping, quét cổng đơn giản, whois v.v. [Trial/Paid] <a href="https://ip-tools.en.softonic.com/" target="_blank" rel="noreferrer">https://ip-tools.en.softonic.com/</a></p><h2 id="angry-ip-scanner" tabindex="-1">Angry IP Scanner <a class="header-anchor" href="#angry-ip-scanner" aria-label="Permalink to &quot;Angry IP Scanner&quot;">​</a></h2><p>Angry IP Scanner là một trình quét mạng mã nguồn mở và đa nền tảng được thiết kế để quét địa chỉ IP và cổng. [Free software] <a href="https://angryip.org/" target="_blank" rel="noreferrer">https://angryip.org/</a></p><h1 id="cong-cu-proxy-windows" tabindex="-1">Công cụ Proxy Windows <a class="header-anchor" href="#cong-cu-proxy-windows" aria-label="Permalink to &quot;Công cụ Proxy Windows&quot;">​</a></h1><h2 id="proxy-workbench" tabindex="-1">Proxy Workbench <a class="header-anchor" href="#proxy-workbench" aria-label="Permalink to &quot;Proxy Workbench&quot;">​</a></h2><p>Proxy Workbench là một proxy server độc đáo - lý tưởng cho nhà phát triển, chuyên gia bảo mật và giảng viên - hiển thị dữ liệu thời gian thực.</p><p>Daisy Chaining of Proxies có thể làm cho phân tích lưu lượng phức tạp hơn nhiều và khó khăn nhất cho người nghe trộm có thể giám sát các phần khác nhau của Internet. [Free] <a href="https://en.freedownloadmanager.org/Windows-PC/Proxy-Workbench.html" target="_blank" rel="noreferrer">https://en.freedownloadmanager.org/Windows-PC/Proxy-Workbench.html</a></p><h2 id="proxy-switcher" tabindex="-1">Proxy Switcher <a class="header-anchor" href="#proxy-switcher" aria-label="Permalink to &quot;Proxy Switcher&quot;">​</a></h2><p>Proxy Switcher cho phép bạn tự động thực hiện các hành động theo kết nối mạng được phát hiện. Proxy Switcher dành cho tất cả nhu cầu duyệt web ẩn danh. Nó có thể được sử dụng để tránh tất cả các loại giới hạn được áp đặt bởi các trang web khác nhau. Đó có thể là trang tải xuống giới hạn số lượng tải xuống. Hoặc trang video chỉ hoạt động ở một quốc gia cụ thể - hầu hết đều bị đánh bại bởi các tính năng duyệt web ẩn danh mà Proxy Switcher cung cấp. [Trial/Paid] <a href="https://www.proxyswitcher.com/" target="_blank" rel="noreferrer">https://www.proxyswitcher.com/</a></p><h1 id="vpn" tabindex="-1">VPN <a class="header-anchor" href="#vpn" aria-label="Permalink to &quot;VPN&quot;">​</a></h1><h2 id="cyberghost-vpn" tabindex="-1">CyberGhost VPN <a class="header-anchor" href="#cyberghost-vpn" aria-label="Permalink to &quot;CyberGhost VPN&quot;">​</a></h2><p>Phần mềm VPN cho phép bạn lướt web ẩn danh, truy cập nội dung bị chặn hoặc kiểm duyệt. [Paid] <a href="https://www.cyberghostvpn.com/" target="_blank" rel="noreferrer">https://www.cyberghostvpn.com/</a></p><h2 id="proton-vpn" tabindex="-1">Proton VPN <a class="header-anchor" href="#proton-vpn" aria-label="Permalink to &quot;Proton VPN&quot;">​</a></h2><p>Phần mềm VPN cho phép bạn lướt web ẩn danh, truy cập nội dung bị chặn hoặc kiểm duyệt. [Paid] <a href="https://protonvpn.com/" target="_blank" rel="noreferrer">https://protonvpn.com/</a></p><h1 id="cong-cu-kham-pha-mang" tabindex="-1">Công cụ Khám phá Mạng <a class="header-anchor" href="#cong-cu-kham-pha-mang" aria-label="Permalink to &quot;Công cụ Khám phá Mạng&quot;">​</a></h1><h2 id="network-topology-mapper" tabindex="-1">Network Topology Mapper <a class="header-anchor" href="#network-topology-mapper" aria-label="Permalink to &quot;Network Topology Mapper&quot;">​</a></h2><p>SolarWinds Network Topology Mapper tự động khám phá mạng của bạn và tạo sơ đồ mạng toàn diện có thể dễ dàng xuất sang MS Office. Network Topology Mapper tự động phát hiện thiết bị mới và thay đổi cấu trúc liên kết mạng. Nó đơn giản hóa quản lý tài sản phần cứng và phần mềm, đáp ứng nhu cầu báo cáo cho tuân thủ PCI và các yêu cầu quy định khác. [Trial/Paid] <a href="https://www.solarwinds.com/network-topology-mapper" target="_blank" rel="noreferrer">https://www.solarwinds.com/network-topology-mapper</a></p>',24)]))}const u=t(r,[["render",e]]);export{d as __pageData,u as default};
